// Process LLM response and extract enhanced prompt
const body = $input.first().json || {};
const validatedInput = $('Validate Input').first().json || {};

const choices = body.choices || [];
const enhancedPrompt = choices[0]?.message?.content || '';

if (!enhancedPrompt) {
  return [{
    json: {
      valid: false,
      error: 'LLM failed to generate an enhanced prompt',
      raw_response: JSON.stringify(body)
    }
  }];
}

return [{
  json: {
    valid: true,
    original_prompt: validatedInput.prompt,
    enhanced_prompt: enhancedPrompt.trim().slice(0, 1000),
    channel: validatedInput.channel,
    timestamp: new Date().toISOString()
  }
}];

