// Process ComfyUI response
const body = $input.first().json || {};
const llmResponse = $('Process LLM Response').first().json || {};

const promptId = body.prompt_id || 'unknown';
const number = body.number || 0;

return [{
  json: {
    success: !!promptId && promptId !== 'unknown',
    prompt_id: promptId,
    queue_number: number,
    original_prompt: llmResponse.original_prompt || '',
    enhanced_prompt: llmResponse.enhanced_prompt || '',
    channel: llmResponse.channel || 'general',
    timestamp: new Date().toISOString()
  }
}];
